webpackJsonp([0xa3a2665d247a],{479:function(e,a){e.exports={data:{site:{siteMetadata:{title:"Jeffry.in",author:"Jeff Wainwright"}},markdownRemark:{id:"/Users/jeff/Dropbox/me/git-docs/yowainwright.github.io/src/pages/2017-03-14-git-update-tag.md absPath of file >>> MarkdownRemark",html:'<p><a href="https://git-scm.com/book/en/v2/Git-Basics-Tagging">Git tags</a> are used for establishing versions of products. They usually use <a href="http://semver.org/">Semver Versioning</a>. </p>\n<p>Because tags often specify specific changes in code, sometimes updates need to be added to specific tags. This update can be made in a few simple steps.</p>\n<p>Establish tags</p>\n<div class="gatsby-highlight">\n      <pre class="language-bash"><code class="language-bash">git tag</code></pre>\n      </div>\n<p>Delete tag</p>\n<div class="gatsby-highlight">\n      <pre class="language-bash"><code class="language-bash">git push origin :refs/tags/[tag version]</code></pre>\n      </div>\n<p>Finally, re-create the tag by following your initial steps for setting up git tags. </p>',frontmatter:{featured_image:null,meta:"This post instructs how to update git tags after they've been pushed",title:"Updating Git Tags That Have Been Pushed",date:"March 14, 2017",path:"/git-tag-update/"}}},pathContext:{}}}});
